import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";

function DashboardPage() {
  const [darkMode, setDarkMode] = useState(false);
  const [username, setUsername] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    const user = localStorage.getItem("username");
    if (!user) {
      navigate("/login");
    } else {
      setUsername(user);
    }
  }, [navigate]);

  const toggleTheme = () => {
    setDarkMode((prev) => !prev);
  };

  const goToProfile = () => {
    navigate("/profile");
  };

  return (
    <div className={`min-vh-100 py-4 ${darkMode ? "bg-dark text-light" : "bg-light text-dark"}`}>
      <div className="container">
        {/* Top Bar */}
        <div className="d-flex justify-content-between align-items-center mb-4">
          <h2>📊 Dashboard</h2>
          <div className="d-flex align-items-center gap-3">
            <button onClick={toggleTheme} className="btn btn-outline-secondary btn-sm">
              {darkMode ? "☀️ Light Mode" : "🌙 Dark Mode"}
            </button>
            <button onClick={goToProfile} className="btn btn-outline-primary btn-sm">
              Profile
            </button>
          </div>
        </div>

        {/* Welcome Message */}
        <div className="text-center mb-4">
          <h4>
            Welcome, <span className="text-primary fw-bold">{username}</span>!
          </h4>
        </div>

        {/* Dashboard Cards */}
        <div className="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
          {[
            { to: "/students", icon: "📚", title: "Students", text: "Manage all registered students.", bg: "secondary", textColor: "white" },
            { to: "/teachers", icon: "👨‍🏫", title: "Teachers", text: "View and update teacher records.", bg: "success", textColor: "white" },
            { to: "/subjects", icon: "📘", title: "Subjects", text: "Explore subjects offered by the school.", bg: "primary", textColor: "white" },
            { to: "/classrooms", icon: "🏫", title: "Classrooms", text: "Assign students and teachers to classes.", bg: "danger", textColor: "white" },
            { to: "/timetable", icon: "📅", title: "Timetable", text: "Manage class schedules and time slots.", bg: "info", textColor: "white" },
            { to: "/attendance", icon: "✅", title: "Attendance", text: "Track daily attendance records.", bg: "warning", textColor: "dark" },
            { to: "/grades", icon: "🏅", title: "Grades", text: "Enter and view student grades.", bg: darkMode ? "light" : "dark", textColor: darkMode ? "dark" : "light" },
          ].map((card, i) => (
            <div className="col" key={i}>
              <Link to={card.to} className="text-decoration-none">
                <div className={`card bg-${card.bg} text-${card.textColor} h-100 shadow`}>
                  <div className="card-body text-center">
                    <h5 className="card-title">{card.icon} {card.title}</h5>
                    <p className="card-text">{card.text}</p>
                  </div>
                </div>
              </Link>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default DashboardPage;
